import { Collection, Filter, MongoServerError } from 'mongodb';

import { getDocumentIndexFields } from './document-index-fields.ts';
import { mongoFindMany } from './mongo-loader';
import { createIndexBasedFilters, parseAttributeFilters } from './parse-attribute-filters.ts';

import { createDocumentIndexBasedFilters } from './createDocumentIndexBasedFilters.ts';

import { assertError, nonNullValues } from 'powership';
import { DocumentIndex } from './document-index.ts';

import { mergeIndexRelationsResult } from './merge-relation-results.ts';
import { parseMongoUpdateExpression } from './parse-mongo-update.ts';
import { parseUpdateExpression } from './parse-update-expressions.ts';
import {
  CreateOneConfig,
  CreateOneResult,
  DEFAULT_SORT,
  DeleteManyConfig,
  DeleteManyResult,
  DeleteOneConfig,
  DeleteOneResult,
  DocumentLoaders,
  FindByIdConfig,
  FindManyConfig,
  FindManyResult,
  FindOneConfig,
  FindOneResult,
  PaginationResult,
  UpdateManyConfig,
  UpdateManyResult,
  UpdateOneConfig,
  UpdateOneResult,
} from './query-types.ts';

export class DocumentClient implements DocumentLoaders {
  constructor(readonly collection: Collection) {}

  async createOne(options: CreateOneConfig): Promise<CreateOneResult<any>> {
    const { item: itemInput, indexConfig, replace = false } = options;

    const res: CreateOneResult<any> = {
      created: false,
      item: null,
      updated: false,
      error: null,
    };

    const indexMap = getDocumentIndexFields(itemInput, indexConfig);

    if (indexMap.error) {
      throw indexMap.error;
    }

    const defaultFields = indexMap.indexFields;
    const item = {
      ...itemInput,
      ...defaultFields,
    };

    const collection = this.collection;

    const conditionExpression: Filter<any> = {};

    if (options.condition) {
      conditionExpression.$and = conditionExpression.$and || [];
      conditionExpression.$and.push(...parseAttributeFilters(options.condition));
    }

    const notRepeat$OR: Filter<any>[] = [];

    indexMap.parsedIndexKeys.forEach(({ PK, SK }) => {
      const item = {
        [PK.destinationField.key]: PK.destinationField.value,
      };
      if (SK) {
        item[SK.destinationField.key] = SK.destinationField.value;
      }
      notRepeat$OR.push(item);
    });

    if (notRepeat$OR.length === 1) {
      Object.assign(conditionExpression, notRepeat$OR[0]);
    } else {
      conditionExpression.$or = [
        ...(conditionExpression.$or || []),
        ...notRepeat$OR,
      ];
    }

    try {
      if (replace) {
        const result = await collection.replaceOne(conditionExpression, item, {
          hint: { _id: 1 },
          upsert: true,
        });

        const updated = result?.modifiedCount === 1;
        const upsertedId = result?.upsertedId;

        res.created = !updated;
        res.updated = updated;
        res.item = {
          ...item,
          _id: upsertedId || item._id,
        };
      } else {
        const result = await collection.findOneAndUpdate(
          conditionExpression,
          { $setOnInsert: item },
          {
            hint: { _id: 1 },
            upsert: true,
            includeResultMetadata: true,
          },
        );

        const data = result.lastErrorObject || {};

        if (data.updatedExisting) {
          throw new Error(
            //   FIXME - something like `A document with the specified index already exists. Conflicting fields: [field1, field2]`
            `Can't create two documents with same index. Existing document found with ${JSON.stringify(
              {
                notRepeat$OR,
                data,
              },
              null,
              2,
            )}`,
          );
        }

        const created = !!data.upserted;

        res.created = created;
        res.updated = false;
        res.item = created ? item : null;
      }
    } catch (e) {
      res.error = parseMongoError(e);
    }

    return res;
  }

  async findMany(options: FindManyConfig): Promise<FindManyResult> {
    const {
      filter,
      sort: sortInit = DEFAULT_SORT,
      projection,
      first,
      after,
      indexConfig,
      condition,
    } = options;

    const { relationFilters, indexFilter } = createDocumentIndexBasedFilters(filter, indexConfig);

    const $and = parseAttributeFilters(indexFilter);

    const relationsQuery = (() => {
      if (!relationFilters?.length) return undefined;
      return parseAttributeFilters({ $or: relationFilters })[0];
    })();

    const sortKey = (() => {
      for (let idx of indexConfig.indexes) {
        if (idx.SK?.length) {
          return DocumentIndex.parseFieldName(idx.name, 'SK');
        }
      }
      return '_id';
    })();

    if (after) {
      const { indexFilter } = createDocumentIndexBasedFilters(
        typeof after === 'string' ? { id: after } : after,
        indexConfig,
      );

      // @ts-ignore
      const indexFilterElement = indexFilter[sortKey];

      if (typeof indexFilterElement === 'string') {
        $and.push({
          [sortKey]: {
            [sortInit === 'DESC' ? '$lt' : '$gt']: indexFilterElement,
          },
        });
      } else {
        $and.push({
          _id: {
            [sortInit === 'DESC' ? '$lt' : '$gt']: nonNullValues(
              {
                _id: indexFilter._id,
              },
              'Failed to mount "after" condition.',
            )._id,
          },
        });
      }
    }

    if (condition) {
      const _conditions = parseAttributeFilters(condition);
      $and.push(..._conditions);
    }

    const query = $and.length > 1 ? { $and } : $and[0];

    const collection = this.collection;

    const sortParsed = { [sortKey]: sortInit === 'DESC' ? -1 : 1 } as const;
    const onlyOne = first === 1;

    async function _relationsQuery() {
      if (!relationsQuery) return null;

      return mongoFindMany(
        {
          query: relationsQuery,
          collection,
        },
        options.context,
      );
    }

    async function _mainEntityQuery() {
      if (onlyOne) {
        const result = await mongoFindMany(
          {
            collection,
            onlyOne,
            projection: projection,
            query,
            sort: sortParsed,
          },
          options.context,
        );

        if (result) {
          return onlyOne ? [result] : result;
        } else {
          return [];
        }
      }
      return collection
        .find(query, {
          limit: first,
          projection,
          sort: sortParsed,
        })
        .toArray();
    }

    const { items, error } = await (async () => {
      try {
        const all = await Promise.all([
          _mainEntityQuery(),
          _relationsQuery(),
        ]);

        return {
          items: (() => {
            const [main, relations] = all;
            if (!relations) return main;

            return mergeIndexRelationsResult({
              items: [
                ...main,
                ...relations,
              ],
              indexConfig,
            });
          })(),
          error: null,
        };
      } catch (e) {
        return {
          items: null,
          all: [],
          error: parseMongoError(e),
        };
      }
    })();

    if (!items) {
      throw error;
    }

    return { items };
  }

  async paginate(options: FindManyConfig): Promise<PaginationResult> {
    const limit = options.first !== undefined ? options.first + 1 : undefined;

    const { items } = await this.findMany({
      ...options,
      first: limit,
    });

    const edges = items.map((item) => ({
      cursor: item._id,
      node: item,
    }));

    let hasNextPage = !!(options.first && items.length > options.first);

    if (hasNextPage) {
      edges.pop();
    }

    return {
      edges,
      pageInfo: {
        endCursor: edges[edges.length - 1]?.cursor,
        hasNextPage,
        hasPreviousPage: !!options.after,
        startCursor: edges[0]?.cursor,
      },
    };
  }

  async findOne(options: FindOneConfig): Promise<FindOneResult> {
    const { filter, projection, consistent, indexConfig, context, condition } = options;

    const { items } = await this.findMany({
      condition,
      consistent,
      context,
      filter,
      first: 1,
      indexConfig,
      projection,
    });

    return {
      item: items?.[0] ?? null,
    };
  }

  async findById(options: FindByIdConfig): Promise<FindOneResult> {
    const { id, projection, consistent, indexConfig, context, condition } = options;

    return await this.findOne({
      condition,
      consistent,
      context,
      filter: { id },
      indexConfig,
      projection,
    });
  }

  private parseUpdateParams(
    options:
      | {
          kind: 'updateOne';
          params: UpdateOneConfig;
        }
      | {
          kind: 'updateMany';
          params: UpdateManyConfig;
        }
  ) {
    const { update, upsert, indexConfig, filter, condition } = options.params;

    const parsedFilter = createIndexBasedFilters({
      filter,
      indexConfig,
    });

    const parsedUpdate = parseUpdateExpression(update, indexConfig);
    const updateExpression = parseMongoUpdateExpression(parsedUpdate);
    const collection = this.collection;

    if (condition) {
      parsedFilter.push(...parseAttributeFilters(condition));
    }

    return {
      collection,
      condition,
      filter,
      indexConfig,
      parsedFilter,
      parsedUpdate,
      update,
      updateExpression,
      upsert,
    };
  }

  async updateOne(options: UpdateOneConfig): Promise<UpdateOneResult> {
    const { upsert, updateExpression, collection, parsedFilter } = this.parseUpdateParams({
      kind: 'updateOne',
      params: options,
    });

    try {
      const result = await collection.findOneAndUpdate(
        { $and: parsedFilter },
        // @ts-ignore
        updateExpression,
        {
          returnDocument: 'after',
          includeResultMetadata: true,
          upsert,
        },
      );

      const { updatedExisting, upserted } = result.lastErrorObject || {};

      return {
        created: !!upserted,
        item: result.value as any,
        updated: !!updatedExisting,
        error: null,
      };
    } catch (e) {
      return {
        created: false,
        error: parseMongoError(e),
        item: null,
        updated: false,
      };
    }
  }

  async updateMany(options: UpdateManyConfig): Promise<UpdateManyResult> {
    const { upsert, updateExpression, collection, parsedFilter } = this.parseUpdateParams({
      kind: 'updateMany',
      params: options,
    });

    try {
      const result = await collection.updateMany(
        { $and: parsedFilter },
        // @ts-ignore
        updateExpression,
        {
          upsert,
        },
      );

      const { modifiedCount, upsertedId } = result;

      return {
        modifiedCount,
        upsertedId: upsertedId ? upsertedId.toString() : null,
      };
    } catch (e) {
      return {
        error: parseMongoError(e),
        modifiedCount: null,
        upsertedId: null,
      };
    }
  }

  async deleteOne(options: DeleteOneConfig): Promise<DeleteOneResult> {
    const { indexConfig, condition, filter } = options;

    const parsedFilter = createIndexBasedFilters({
      filter,
      indexConfig,
    });

    const collection = this.collection;

    if (condition) {
      parsedFilter.push(...parseAttributeFilters(condition));
    }

    const { value } = await collection.findOneAndDelete(
      { $and: parsedFilter },
      { includeResultMetadata: true },
    );

    return { item: value as any };
  }

  async deleteMany(options: DeleteManyConfig): Promise<DeleteManyResult> {
    const { indexConfig, condition, filter } = options;

    const parsedFilter = createIndexBasedFilters({
      filter,
      indexConfig,
    });

    const collection = this.collection;

    if (condition) {
      parsedFilter.push(...parseAttributeFilters(condition));
    }

    const { deletedCount } = await collection.deleteMany({
      $and: parsedFilter,
    });

    return { deletedCount };
  }

  static create(collection: Collection) {
    return new DocumentClient(collection);
  }
}

function parseMongoError(error: unknown) {
  assertError(error);
  if (!isMongoServerError(error)) return error.message;
  return error.message + '\n' + JSON.stringify(error?.errInfo?.details, null, 1);
}

function isMongoServerError(error: unknown): error is MongoServerError {
  assertError(error);
  return error.name === 'MongoServerError';
}

