import {
  AnyDocumentIndexConfig,
  DocumentBase,
  DocumentClient,
  DocumentConfigIndexes,
  DocumentIndex,
  LoaderNames,
} from '../index.ts';

import { TObject, TProperties, Type } from '@sinclair/typebox';
import * as Codegen from '@sinclair/typebox-codegen';
import { TypeCheck } from '@utils/type-check.ts';
import { Db } from 'mongodb';
import { captureStackTrace, Compute, invariant, Merge } from 'powership';
import { EntityLoader } from './entity-loader.ts';

// prettier-ignore
export interface EntityLoaders<
  InputType extends TObject,
  Indexes extends DocumentConfigIndexes<DocumentBase>,
> {
  createOne: EntityLoader.Loader<'createOne', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  findById: EntityLoader.Loader<'findById', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  findMany: EntityLoader.Loader<'findMany', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  findOne: EntityLoader.Loader<'findOne', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  updateOne: EntityLoader.Loader<'updateOne', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  updateMany: EntityLoader.Loader<'updateMany', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  deleteOne: EntityLoader.Loader<'deleteOne', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  deleteMany: EntityLoader.Loader<'deleteMany', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  paginate: EntityLoader.Loader<'paginate', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
}

// prettier-ignore
export interface TEntity<
  Object extends TObject,
  Indexes extends DocumentConfigIndexes<DatabaseDocumentType<Object>>
> extends EntityLoaders<Object, Indexes> {
  readonly $inputType: Object;
  readonly $name: string;
  readonly $indexes: Indexes;
  readonly type: TObject
  checkInput: TypeCheck<Object>['parse'];
  setupDatabase(): Promise<void>
}

export namespace Entity {
  const ULID_TYPE = Type.String({
    pattern: '^[0123456789ABCDEFGHJKMNPQRSTVWXYZ]{26}$',
  });

  function getDatabaseFields(
    indexConfig: AnyDocumentIndexConfig
  ) {
    const { indexes } = indexConfig;
    const entity = indexConfig.entity.toLowerCase();
    const { INDEX_PART_SEP, RELATION_PRECEDES } = DocumentIndex;

    return indexes.reduce((acc: any, index) => {
      const PKRegex = (() => {
        if (index.relatedTo) {
          const relName = index.relatedTo.toLowerCase();
          return `^${relName}${INDEX_PART_SEP}${index.name}${INDEX_PART_SEP}[^${RELATION_PRECEDES}]*${RELATION_PRECEDES}${entity}${INDEX_PART_SEP}.*`;
        }
        return `^${entity}${INDEX_PART_SEP}${index.name}${INDEX_PART_SEP}.*`;
      })();

      const PKName = DocumentIndex.parseFieldName(index.name, 'PK');

      const fields = {
        _v: ULID_TYPE,
        ulid: ULID_TYPE,
        createdAt: Type.Date(),
        createdBy: Type.Union(
          [
            Type.String(),
            Type.Null(),
          ],
          { default: null },
        ),
        updatedAt: Type.Date(),
        updatedBy: Type.Union(
          [
            Type.String(),
            Type.Null(),
          ],
          { default: null },
        ),
        _id:
          acc._id ||
          Type.String({
            pattern: PKRegex,
            $id: `Entity${indexConfig.entity}_id`,
            description: `The full string value of the first index following the RegExp format "${PKRegex}"`,
          }),
        [PKName]: Type.String({
          pattern: PKRegex,
          $id: `Entity${indexConfig.entity}${PKName === '_id' ? '_id_' : PKName}`,
          description: `The ${PKName} field in the RegExp format "${PKRegex}"`,
        }),
      };

      if (index.SK?.length) {
        const SKName = DocumentIndex.parseFieldName(index.name, 'SK');
        fields[SKName] = Type.String({
          $id: `Entity${indexConfig.entity}${SKName}`,
          description: `The ${SKName} field.`,
        });
      }

      return {
        ...acc,
        ...fields,
      };
    }, {});
  }

  const Entities = new Map<string, TEntity<any, any>>();
  const EntityByCollection = new Map<string, TEntity<any, any>[]>();

  export function clearEntityMap() {
    Entities.clear();
    EntityByCollection.clear();
  }

  export function create<
    Properties extends TProperties,
    Object extends TObject<Properties>,
    Indexes extends DocumentConfigIndexes<DatabaseDocumentType<Object>>,
  >(
    definition: {
      name: string;
      type: Object;
      indexes: Indexes;
      client: DocumentClient;
    }
  ): TEntity<Object, Indexes> {
    //
    // definitions
    const { name: $name, type: $inputType, indexes: $indexes, client: documentClient } = definition;

    if (Entities.has($name)) {
      console.warn(`Redefining entity with name "${$name}".`);
    }

    DocumentIndex.checkConfig({
      entity: $name,
      indexes: $indexes,
    });

    const databaseType = Type.Object(
      {
        ...$inputType.properties,
        ...getDatabaseFields({
          indexes: $indexes,
          entity: $name,
        }),
      },
      {
        additionalProperties: false,
      },
    );

    {
      // checking index composition
      $indexes.forEach((index) => {
        const check = (field: string) => {
          if (field[0] !== '.') return;
          const name = field.slice(1);
          const exists = databaseType.properties[name];
          if (exists) return;
          const message =
            `Failed to mount index "${index.name}".\n` +
            `Expected field "${name}" to be part of the entity type.`;
          throw new Error(message);
        };
        index.PK.forEach(check);
        index.SK?.forEach(check);
      });
    }

    const checkInput = TypeCheck($inputType) as unknown as TypeCheck<Object>;

    const resolvers: EntityLoaders<Object, Indexes> = Object.create(null);

    LoaderNames.forEach((methodName) => {
      const loader = EntityLoader.Create({
        entityName: $name,
        methodName,
        databaseType,
        documentClient,
        indexes: $indexes,
        inputType: $inputType,
      });

      async function entityLoader(params: never) {
        try {
          return await loader(params);
        } catch (error) {
          captureStackTrace(error, entityLoader);
          throw error;
        }
      }

      Object.defineProperties(entityLoader, {
        name: { value: `${$name}.${methodName}` },
      });

      resolvers[methodName] = entityLoader as never;
    });

    const { collectionName } = documentClient.collection;

    async function setupDatabase() {
      // @ts-ignore private field
      const db = documentClient.collection.s.db as Db;

      const collections = await db.collections();
      const collection = collections.find((el) => {
        return el.collectionName === collectionName;
      });

      const $jsonSchema = (() => {
        const entities = EntityByCollection.get(collectionName) || [];
        invariant(entities.length, `Failed to find entities by collection "${collectionName}".`);

        return Codegen.ModelToMongoDBSchema.Generate({
          types: entities.map((el) => el.type),
        });
      })();

      if (collection) {
        await db.command({
          collMod: collectionName,
          validator: $jsonSchema,
          validationLevel: 'strict',
          validationAction: 'error',
        });
      } else {
        await db.createCollection(collectionName, {
          validator: $jsonSchema,
          validationLevel: 'strict',
          validationAction: 'error',
        });
      }
    }

    const entity: TEntity<Object, Indexes> = {
      $indexes,
      $inputType,
      $name,
      checkInput: checkInput.parse,
      setupDatabase,
      type: databaseType,
      ...resolvers,
    };

    Entities.set($name, entity);
    EntityByCollection.set(
      collectionName,
      (() => {
        const current = EntityByCollection.get(collectionName) || [];
        return [
          ...current,
          entity,
        ];
      })(),
    );

    return entity;
  }
}

export type _PickSK<Indexes> =
  Indexes extends ReadonlyArray<{
    name: infer IndexName extends string;
    SK: ReadonlyArray<string>;
    PK: ReadonlyArray<string>;
    [K: string]: any;
  }>
    ? {
        [L in `${IndexName}SK`]: string;
      }
    : {};

export type _PickPK<Indexes> =
  Indexes extends ReadonlyArray<{
    name: infer IndexName extends string;
    [K: string]: any;
  }>
    ? {
        [L in `${IndexName}PK`]: string;
      }
    : { [L in `${string}PK`]: unknown };

export type DatabaseDocumentType<
  Document extends DocumentBase,
  // prettier-ignore
  Indexes extends DocumentConfigIndexes<DocumentBase> = DocumentConfigIndexes<DocumentBase>,
> = Merge<
  {
    _v: string;
    _id: string;
    createdAt: Date;
    createdBy: string | undefined;
    ulid: string;
    updatedAt: Date;
    updatedBy: string | undefined;
  },
  Merge<Merge<Document, _PickPK<Indexes>>, _PickSK<Indexes>>
>;

