import {
  CreateOne,
  DocumentBase,
  DocumentClient,
  DocumentConfigIndexes,
  DocumentIndexItem,
  DocumentLoaderInput,
  DocumentLoaderName,
  DocumentLoaderOperation,
  DocumentLoaderResult,
  DocumentLoaders,
  getDocumentIndexFields,
  IndexMethods,
} from '../index.ts';

import { Static, TObject } from '@sinclair/typebox';
import { TypeCheck } from '@utils/type-check.ts';
import { assertError, MaybePromise, Merge, PromiseType, ulid } from 'powership';
import { DatabaseDocumentType } from './entity.ts';

export namespace EntityLoader {
  export type InternalContextWithResult = Merge<
    InternalContext,
    { result: PromiseType<ReturnType<DocumentLoaders[keyof DocumentLoaders]>> }
  >;

  // prettier-ignore
  export type EntityLoaderPlugins = {
    beforeStart?: (
      context: InternalContext,
    ) => MaybePromise<InternalContext>;
    afterStart?: (
      context: InternalContext,
    ) => MaybePromise<InternalContext>;    
    beforeExit?: (
      context: InternalContextWithResult,
    ) => MaybePromise<InternalContext>;
  };

  export type CreateLoaderParams<
    Method extends DocumentLoaderName,
    InputType extends TObject,
    // prettier-ignore
    Indexes extends ReadonlyArray<DocumentIndexItem<keyof DatabaseDocumentType<InputType>>>,
  > = {
    indexes: Indexes;
    methodName: Method;
    documentClient: DocumentClient;
    inputType: InputType;
    databaseType: TObject;
    entityName: string;
    plugins?: EntityLoaderPlugins;
  };

  export type InternalContext<Method extends DocumentLoaderName = DocumentLoaderName> =
    // prettier-ignore
    {
      databaseTypeCheck: TypeCheck<DocumentBase>,
      inputTypeCheck: TypeCheck<DocumentBase>,
      databaseTypeCheckPartialExtra: TypeCheck<DocumentBase>,
      inputTypeCheckPartialExtra: TypeCheck<DocumentBase>,
      result: null | PromiseType<ReturnType<DocumentLoaders[Method]>>
    } &
    CreateLoaderParams<Method, TObject, DocumentConfigIndexes<DocumentBase>> &
    DocumentLoaderOperation.Value<Method>;

  function ParsePartialDocument<Document extends DocumentBase>(
    document: Document,
    context: InternalContext
  ): Document {
    // Pre parsing fields that may be formated before filtering or updating
    // It is needed also for filters on updates using upsert:true,
    // because mongo include filters in the possible generated document.
    let preParsed = Object.create(null);
    Object.entries(document).forEach(([k, v]) => {
      if (typeof v === 'string' || typeof v === 'number') {
        if (k.includes('.')) return;
        if (k.includes('[')) return;
        preParsed[k] = v;
      }
    });
    try {
      preParsed = context.inputTypeCheckPartialExtra.parse(preParsed);
    } catch (e: any) {}

    return Object.assign(document, preParsed);
  }

  // OnUpdate
  async function OnUpdate(
    doc: DocumentBase,
    operation: InternalContext
  ) {
    doc.updatedAt = new Date();

    if (!('updatedBy' in doc)) {
      const updatedBy = await operation.context?.userId?.(false);
      if (updatedBy) {
        doc.updatedBy = updatedBy;
      }
    }

    doc._v = ulid();
    return doc;
  }

  // OnCreate
  async function OnCreate(
    document: DocumentBase,
    operation: InternalContext
  ) {
    await OnUpdate(document, operation);

    document.ulid = (() => {
      if (document.ulid) return document.ulid;
      return ulid();
    })();

    document.createdAt = new Date();

    if (!('createdBy' in document)) {
      const createdBy = await operation.context?.userId?.(false);
      if (createdBy) {
        document.createdBy = createdBy;
      }
    }

    document = ParsePartialDocument(document, operation);

    const parsedIndexes = getDocumentIndexFields(document, {
      entity: operation.entityName,
      indexes: operation.indexes,
    });

    if (!parsedIndexes.valid) {
      throw parsedIndexes.error;
    }

    document = {
      ...document,
      ...parsedIndexes.indexFields,
    };

    if (!document.id) {
      // document.id = parsedIndexes.indexFields._c;
    }

    return operation.databaseTypeCheck.parse(document);
  }

  // OnContext
  async function OnContext(context: InternalContext) {
    if (context.isUpdate) {
      context.loaderParams.update.$set = await OnUpdate(
        {
          ...context.loaderParams.update.$set,
        },
        context,
      );

      if (context.isUpsert) {
        const processedDoc = await OnCreate(
          {
            ...context.loaderParams.update.$setIfNull,
            ...context.loaderParams.update.$setOnInsert,
            ...context.loaderParams.update.$set,
          },
          context,
        );

        const originalSetFields = new Set(
          Object.keys(context.loaderParams.update.$set || {}).map((el) => el.split('.')[0]),
        );

        const setFields: DocumentBase = {};
        const setOnInsertFields: DocumentBase = {};

        for (const [key, value] of Object.entries(processedDoc)) {
          if (originalSetFields.has(key)) {
            setFields[key] = value;
          } else {
            setOnInsertFields[key] = value;
          }
        }

        context.loaderParams.update.$set = setFields;
        context.loaderParams.update.$setOnInsert = setOnInsertFields;
        delete context.loaderParams.update.$setIfNull;

        const conflictingFields = Object.keys(setFields).filter((key) => key in setOnInsertFields);

        if (conflictingFields.length > 0) {
          throw new Error(
            `Found conflicting fields in update operators: ${conflictingFields.join(', ')}`,
          );
        }
      } else {
        if (context.loaderParams.update.$setIfNull) {
          context.loaderParams.update.$setIfNull = ParsePartialDocument(
            context.loaderParams.update.$setIfNull,
            context,
          );
        }

        if (context.loaderParams.update.$set) {
          context.loaderParams.update.$set = ParsePartialDocument(
            context.loaderParams.update.$set,
            context,
          );
        }
      }
      //  ======= close update handling ====
    }

    if (context.isCreate) {
      context.loaderParams.item = await OnCreate(context.loaderParams.item, context);
    }

    return context;
  }

  export class LoaderError extends Error {
    readonly name = 'LoaderError';
    readonly $name = 'LoaderError';

    constructor(
      readonly originalError: unknown,
      readonly entityName: string,
      readonly methodName: string
    ) {
      assertError(originalError);
      const message = originalError.message;
      const new_message = `${entityName}.${methodName} ‣ ${message}`;
      const new_stack = originalError.stack.replace(`Error: ${message}\n`, '');
      super(new_message);
      this.stack = new_stack;
    }
  }

  // prettier-ignore
  export type Loader<
      Method extends DocumentLoaderName,
      InputType extends TObject,
      Indexes extends DocumentConfigIndexes<DocumentBase>,
  > = Method extends unknown
    ? Static<InputType> extends infer Input extends DocumentBase
    ? DatabaseDocumentType<Input, Indexes> extends infer Document extends DocumentBase
          ? [Method] extends ['createOne']
            ? CreateOne<Input, Document, Indexes>
            : IndexMethods<Document, Indexes>[Method]
          : never
        : never
        : never

  /**
   *
   * @param createLoaderParams
   * @constructor
   */
  export function Create<
    Method extends DocumentLoaderName,
    InputType extends TObject,
    Indexes extends DocumentConfigIndexes<DocumentBase>,
  >(
    createLoaderParams: CreateLoaderParams<Method, InputType, Indexes>
  ): Loader<Method, InputType, Indexes> {
    const { methodName, documentClient, databaseType, inputType, indexes, entityName, plugins } =
      createLoaderParams;

    const indexConfig = {
      entity: entityName,
      indexes,
    };

    type LoaderInout = DocumentLoaderInput<Method>;
    type Output = DocumentLoaderResult<Method>;
    type Resolver = (config: LoaderInout) => Promise<Output>;

    const databaseTypeCheck: TypeCheck<DocumentBase> = TypeCheck(databaseType);
    const inputTypeCheck: TypeCheck<DocumentBase> = TypeCheck(inputType);
    const databaseTypeCheckPartialExtra: TypeCheck<DocumentBase> = TypeCheck(databaseType, {
      partial: true,
      additionalProperties: true,
    });
    const inputTypeCheckPartialExtra: TypeCheck<DocumentBase> = TypeCheck(inputType, {
      partial: true,
      additionalProperties: true,
    });

    let Resolver = documentClient[methodName].bind(documentClient) as Resolver;

    async function Loader(loaderParams: LoaderInout): Promise<Output> {
      let context = {
        result: null,
        databaseTypeCheck,
        inputTypeCheck,
        databaseTypeCheckPartialExtra,
        inputTypeCheckPartialExtra,
        ...DocumentLoaderOperation.Generate({
          method: methodName,
          loaderParams: {
            ...loaderParams,
            indexConfig,
          },
          context: loaderParams.context,
        }),
        ...createLoaderParams,
      } as InternalContext;

      try {
        try {
          if (plugins?.beforeStart) {
            context = await plugins.beforeStart(context);
          }
          context = await OnContext(context);
          if (plugins?.afterStart) {
            context = await plugins.afterStart(context);
          }
        } catch (error) {
          assertError(error);
          return {
            error: new LoaderError(error, entityName, methodName).message,
          } as never;
        }

        context.result = (await Resolver(context.loaderParams)) as never;

        if (plugins?.beforeExit) {
          context = await plugins.beforeExit(context as InternalContextWithResult);
        }

        return context.result as never;
      } catch (error) {
        throw new LoaderError(error, entityName, methodName);
      }
    }

    Object.defineProperties(Loader, {
      name: { value: methodName },
    });

    return Loader as never;
  }
}

