import { CloneType, Kind, Static, TObject, TSchema } from '@sinclair/typebox';
import { AssertError, Value, ValueError, ValueErrorType } from '@sinclair/typebox/value';
import { captureStackTrace } from 'powership';

export type TypeCheckOptions = {
  additionalProperties?: boolean;
  partial?: boolean;
  message?: string;
};

export type TypeCheck<T> = {
  (value: unknown, message?: string): T;
  parse(value: unknown, message?: string): T;
};

export function TypeCheck<T extends TSchema>(
  type: T,
  options?: TypeCheckOptions | string
): TypeCheck<Static<T>> {
  const {
    message: defaultMessage,
    additionalProperties = false,
    partial = false,
  } = ((): TypeCheckOptions => {
    if (typeof options === 'string') return { message: options };
    return options ?? {};
  })();

  const checkType = (() => {
    if (!IsObjectType(type)) return type;

    const shouldChangeAdditionalProperties = additionalProperties !== type.additionalProperties;
    const shouldChangeRequired = type.required?.length && partial;
    if (!shouldChangeAdditionalProperties && !shouldChangeRequired) {
      return type;
    }

    const cloneType = CloneType(type) as TObject;

    if (shouldChangeAdditionalProperties) {
      cloneType.additionalProperties = additionalProperties;
    }

    if (shouldChangeRequired) {
      cloneType.required = partial ? [] : cloneType.required;
    }

    return cloneType;
  })();

  function Check(
    value: unknown,
    message = defaultMessage
  ) {
    try {
      Value.Assert(checkType, value);
    } catch (e) {
      if (!(e instanceof AssertError)) {
        throw captureStackTrace(e, Check);
      }
      throw captureStackTrace(new TypeCheckError(message, [...e.Errors()]), Check);
    }
    return value;
  }

  Check.parse = function Parse(
    value: unknown,
    message = defaultMessage
  ) {
    try {
      value = Value.Clone(value);
      value = additionalProperties ? value : Value.Clean(checkType, value);
      value = partial ? value : Value.Default(checkType, value);
      Value.Assert(checkType, value);
      return value;
    } catch (e) {
      if (!(e instanceof AssertError)) {
        throw captureStackTrace(e, Check.parse);
      }
      throw captureStackTrace(new TypeCheckError(message, [...e.Errors()]), Check.parse);
    }
  };

  return Check;
}

export function IsObjectType(input: TSchema): input is TObject {
  return input[Kind] === 'Object';
}

export class TypeCheckError extends Error {
  name = 'TypeCheckError';
  errors: ValueError[];
  constructor(
    message: string | undefined,
    errors: ValueError[]
  ) {
    const errorByField: Record<string, ValueError[]> = Object.create(null);

    errors.forEach((error) => {
      errorByField[error.path] = errorByField[error.path] || [];
      errorByField[error.path].push(error);
    });

    let text = Object.entries(errorByField)
      .map(([field, errors]) => {
        if (errors.length > 1 && errors[0].type === ValueErrorType.ObjectRequiredProperty) {
          errors = errors.slice(0, 1);
        }
        let txt = errors.map((error) => error.message).join(', ');
        const key = field.replace(/^\//, '') || '/';
        return `${key}: ${txt}`;
      })
      .join('\n');
    message = message ? `${message} - ${text}` : text;
    super(message);
    this.errors = errors;
  }
}

